// 4. Message belongs to conversation (messages.conversation_id = conversationId)

const { data: { user } } = await supabase.auth.getUser();
if (!user) return unauthorized();

// Verify tenant ownership
const { data: tenant } = await supabase
  .from('tenants')
  .select('id')
  .eq('id', tenantId)
  .eq('user_id', user.id)  // CRITICAL: Check user owns tenant
  .single();
if (!tenant) return forbidden();

// For message operations, also verify conversation ownership
if (conversationId) {
  const { data: conversation } = await supabase
    .from('conversations')
    .select('id')
    .eq('id', conversationId)
    .eq('tenant_id', tenantId)  // CRITICAL: Conversation must belong to tenant
    .single();
  if (!conversation) return forbidden();
}
```

